import { useState, useEffect, useMemo } from "react";
import { useData } from "../contexts/DataContext";
import { Button } from "../components/ui/button";
import { Input } from "../components/ui/input";
import { Label } from "../components/ui/label";
import { Textarea } from "../components/ui/textarea";
import { toast } from "sonner";

// Default data perusahaan agar selalu ada isi
const DEFAULT_COMPANY = {
  name: "PT Maju Bersama Indonesia",
  tagline: "Solusi Terbaik untuk Bisnis Anda",
  description:
    "Perusahaan teknologi yang bergerak di bidang pengembangan software dan konsultasi IT sejak 2015. Kami melayani lebih dari 500 klien di seluruh Indonesia.",
  phone: "+62 21 1234 5678",
  email: "info@majubersama.co.id",
  address:
    "Jl. Sudirman No. 123, Kel. Senayan, Kec. Kebayoran Baru, Jakarta Selatan, DKI Jakarta 12190",
};

export default function ProfilPerusahaan() {
  const { company, setCompany } = useData();

  const [form, setForm] = useState(DEFAULT_COMPANY);
  const [loading, setLoading] = useState(false);

  // Sync dari context; kalau kosong pakai default
  useEffect(() => {
    if (company && Object.keys(company).length > 0) {
      setForm({
        name: company.name ?? DEFAULT_COMPANY.name,
        tagline: company.tagline ?? DEFAULT_COMPANY.tagline,
        description: company.description ?? DEFAULT_COMPANY.description,
        phone: company.phone ?? DEFAULT_COMPANY.phone,
        email: company.email ?? DEFAULT_COMPANY.email,
        address: company.address ?? DEFAULT_COMPANY.address,
      });
    }
  }, [company]);

  // Detect perubahan dari data tersimpan
  const savedData = company && Object.keys(company).length > 0 ? company : DEFAULT_COMPANY;
  const isChanged = useMemo(
    () => JSON.stringify(form) !== JSON.stringify(savedData),
    [form, savedData]
  );

  const handleChange = (key, value) => {
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const validate = () => {
    if (!form.name?.trim()) return "Nama perusahaan wajib diisi";
    if (!form.email?.trim()) return "Email perusahaan wajib diisi";
    return null;
  };

  const handleSave = async () => {
    const error = validate();
    if (error) {
      toast.error(error);
      return;
    }
    try {
      setLoading(true);
      await new Promise((resolve) => setTimeout(resolve, 500));
      setCompany(form);
      toast.success("Profil perusahaan berhasil diperbarui");
    } catch {
      toast.error("Gagal menyimpan data");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-[860px]" data-testid="profil-perusahaan-page">
      <h1 className="text-3xl font-extrabold text-gray-900">
        Profil Perusahaan
      </h1>
      <p className="text-sm text-gray-500 mt-1 mb-8">
        Kelola informasi perusahaan yang tampil ke publik
      </p>

      <div className="mpl-card p-8 bg-white rounded-xl shadow-sm border border-gray-100">
        <h3 className="text-base font-bold text-gray-900 mb-6">
          Informasi Perusahaan
        </h3>

        <div className="space-y-5">
          {/* Nama Perusahaan */}
          <FormField label="Nama Perusahaan">
            <Input
              value={form.name}
              onChange={(e) => handleChange("name", e.target.value)}
              placeholder="Masukkan nama perusahaan"
            />
          </FormField>

          {/* Tagline / Slogan */}
          <FormField label="Tagline/Slogan">
            <Input
              value={form.tagline}
              onChange={(e) => handleChange("tagline", e.target.value)}
              placeholder="Masukkan tagline atau slogan perusahaan"
            />
          </FormField>

          {/* Deskripsi Singkat */}
          <FormField label="Deskripsi Singkat">
            <Textarea
              rows={4}
              value={form.description}
              onChange={(e) => handleChange("description", e.target.value)}
              placeholder="Tuliskan deskripsi singkat tentang perusahaan Anda"
            />
          </FormField>

          {/* No. Telepon & Email — 2 kolom */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <FormField label="No. Telepon">
              <Input
                value={form.phone}
                onChange={(e) => handleChange("phone", e.target.value)}
                placeholder="+62 ..."
              />
            </FormField>

            <FormField label="Email Perusahaan">
              <Input
                type="email"
                value={form.email}
                onChange={(e) => handleChange("email", e.target.value)}
                placeholder="email@perusahaan.com"
              />
            </FormField>
          </div>

          {/* Alamat */}
          <FormField label="Alamat Perusahaan">
            <Textarea
              rows={3}
              value={form.address}
              onChange={(e) => handleChange("address", e.target.value)}
              placeholder="Masukkan alamat lengkap perusahaan"
            />
          </FormField>
        </div>
      </div>

      {/* Tombol simpan — Disesuaikan dengan Gambar */}
      <div className="mt-8 flex justify-center md:justify-end">
        <button
          onClick={handleSave}
          disabled={!isChanged || loading}
          className={`
            min-w-[280px] h-14 px-10 text-lg font-bold transition-all
            rounded-[20px] shadow-sm
            ${!isChanged || loading 
              ? "bg-gray-300 text-gray-500 cursor-not-allowed" 
              : "bg-[#F3A43B] hover:bg-[#e2962f] text-[#1a1a1a] active:scale-[0.98]"}
          `}
        >
          {loading ? "Menyimpan..." : "Simpan Perubahan"}
        </button>
      </div>
    </div>
  );
}

// ===== HELPER COMPONENTS =====
function FormField({ label, children }) {
  return (
    <div>
      <Label className="text-sm text-gray-600 font-medium">{label}</Label>
      <div className="mt-1.5">{children}</div>
    </div>
  );
}
